          '6': { text: 'Ich bemerke oft, wenn jemand sich unwohl f\u00fchlt, auch wenn er es nicht sagt.', options: ['Stimme gar nicht zu', 'Stimme etwas nicht zu', 'Stimme etwas zu', 'Stimme voll zu'] },
          '7': { text: 'Emotionale Szenen in Filmen ber\u00fchren mich stark.', options: ['Stimme gar nicht zu', 'Stimme etwas nicht zu', 'Stimme etwas zu', 'Stimme voll zu'] },
          '8': { text: 'Ich finde es einfach, die Perspektive eines anderen in einem Streit zu verstehen.', options: ['Stimme gar nicht zu', 'Stimme etwas nicht zu', 'Stimme etwas zu', 'Stimme voll zu'] },
          '9': { text: 'Es st\u00f6rt mich, wenn ich sehe, dass jemand ungerecht behandelt wird.', options: ['Stimme gar nicht zu', 'Stimme etwas nicht zu', 'Stimme etwas zu', 'Stimme voll zu'] },
          '10': { text: 'Ich bin gut darin, die Stimmung in einem Raum zu sp\u00fcren.', options: ['Stimme gar nicht zu', 'Stimme etwas nicht zu', 'Stimme etwas zu', 'Stimme voll zu'] },
          '11': { text: 'Ich kann leicht vorhersagen, wie sich jemand in einer bestimmten Situation f\u00fchlen wird.', options: ['Stimme gar nicht zu', 'Stimme etwas nicht zu', 'Stimme etwas zu', 'Stimme voll zu'] },
          '12': { text: 'Wenn ein Freund aufgeregt ist, f\u00fchle ich mich auch aufgeregt.', options: ['Stimme gar nicht zu', 'Stimme etwas nicht zu', 'Stimme etwas zu', 'Stimme voll zu'] },
          '13': { text: 'Ich achte auf den Tonfall von Menschen, um ihre Gef\u00fchle zu verstehen.', options: ['Stimme gar nicht zu', 'Stimme etwas nicht zu', 'Stimme etwas zu', 'Stimme voll zu'] },
          '14': { text: 'Ich finde es manchmal schwer zu verstehen, warum Menschen so reagieren, wie sie es tun.', options: ['Stimme gar nicht zu', 'Stimme etwas nicht zu', 'Stimme etwas zu', 'Stimme voll zu'] },
          '15': { text: 'Ich bin oft die erste Person, die bemerkt, wenn jemand sich zur\u00fcckzieht.', options: ['Stimme gar nicht zu', 'Stimme etwas nicht zu', 'Stimme etwas zu', 'Stimme voll zu'] },
          '16': { text: 'Ich kann die K\u00f6rpersprache anderer gut lesen.', options: ['Stimme gar nicht zu', 'Stimme etwas nicht zu', 'Stimme etwas zu', 'Stimme voll zu'] },
          '17': { text: 'Wenn ich sehe, dass jemand leidet, m\u00f6chte ich helfen.', options: ['Stimme gar nicht zu', 'Stimme etwas nicht zu', 'Stimme etwas zu', 'Stimme voll zu'] },
          '18': { text: 'Ich finde es leicht, mit Fremden ein Gespr\u00e4ch \u00fcber ihre Gef\u00fchle zu f\u00fchren.', options: ['Stimme gar nicht zu', 'Stimme etwas nicht zu', 'Stimme etwas zu', 'Stimme voll zu'] },
          '19': { text: 'Ich verstehe, dass verschiedene Menschen unterschiedlich auf dieselbe Situation reagieren k\u00f6nnen.', options: ['Stimme gar nicht zu', 'Stimme etwas nicht zu', 'Stimme etwas zu', 'Stimme voll zu'] },
